-- --- Screenshots ---

-- bindO - hold to trigger
hl.bind(mainMod .. " + S", hl.dsp.exec_cmd("screenshot --fulltoboth"), { long_press = true })
hl.bind(mainMod .. " + S", hl.dsp.submap("screenshot"))
hl.define_submap("screenshot", function()
  hl.bind(mainMod .. " + F", hl.dsp.exec_cmd("screenshot --fulltoboth"))
  hl.bind(mainMod .. " + SHIFT + F", hl.dsp.exec_cmd("screenshot --fulltoclip"))
  -- 's' for select
  hl.bind(mainMod .. " + S", hl.dsp.exec_cmd("screenshot --parttoclip"))
  hl.bind(mainMod .. " + N", hl.dsp.exec_cmd("screenshot --parttoclipnofreeze"))
  hl.bind(mainMod .. " + SHIFT + S", hl.dsp.exec_cmd("screenshot --parttoboth"))
  -- 'd' for draw
  hl.bind(mainMod .. " + D", hl.dsp.exec_cmd("screenshot --drawtoclip"))
  hl.bind(mainMod .. " + SHIFT + D", hl.dsp.exec_cmd("screenshot --drawtoboth"))
  -- 'o' for OCR
  hl.bind(mainMod .. " + O", hl.dsp.exec_cmd("screenshot --ocr"))
  hl.bind(mainMod .. " + SHIFT + O", hl.dsp.exec_cmd("screenshot --otpdecode"))
  hl.bind(mainMod .. " + R", hl.dsp.exec_cmd("screenshot --ocr-ru"))
  hl.bind(mainMod .. " + bracketleft", hl.dsp.submap("reset"))
  hl.bind("catchall", hl.dsp.submap("reset"))
end)

-- --- Notifications ---

hl.bind(mainMod .. " + N", hl.dsp.submap("notifs"))
hl.define_submap("notifs", function()
  hl.bind(mainMod .. " + N", hl.dsp.exec_cmd("swaync-client -t"))
  hl.bind(mainMod .. " + H", hl.dsp.exec_cmd("swaync-client --hide-latest"))
  -- closes latest only if those are still 'floating', not in control-center
  -- bind = SUPER, C, exec, swaync-client --close-latest
  hl.bind(mainMod .. " + C", hl.dsp.exec_cmd("swaync-client -C"))
  hl.bind(mainMod .. " + R", hl.dsp.exec_cmd("sh ~/.config/swaync/reload.sh"))
  -- default reset to go back to the global submap

  hl.bind(mainMod .. " + bracketleft", hl.dsp.submap("reset"))
  hl.bind("catchall", hl.dsp.submap("reset"))
end)
